import { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { paymentAPI } from '../api';
import toast from 'react-hot-toast';

const Upgrade = () => {
  const { user, updateUserPlan } = useAuth();
  const [loading, setLoading] = useState(false);

  const handleUpgrade = async () => {
    setLoading(true);
    try {
      const res = await paymentAPI.createOrder();
      const { order, key, user: u, amount } = res.data;

      const options = {
        key,
        amount,
        currency: 'INR',
        name: 'Limitly Pro',
        description: 'Monthly SaaS Subscription',
        order_id: order.id,
        handler: async (response) => {
          try {
            await paymentAPI.verify(response);
            toast.success('🎉 Welcome to Pro! Your account is now upgraded.');
            updateUserPlan('pro');
          } catch {
            toast.error('Payment verification failed. Please contact support.');
          }
        },
        prefill: { name: u.name, email: u.email },
        theme: { color: '#D9FF00' },
      };

      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (err) {
      toast.error('Razorpay keys are missing or invalid in .env.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: '900px', margin: '0 auto', textAlign: 'center' }}>
      <div style={{ marginBottom: '3rem' }}>
        <h1 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: '0.5rem' }}>Power up your workflow</h1>
        <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>Choose the plan that fits your growth.</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '2rem' }}>

        {/* Free Plan */}
        <div style={cardStyle}>
          <div style={badgeStyle('rgba(148, 163, 184, 0.1)', '#94a3b8')}>BASIC</div>
          <div style={{ fontSize: '2.5rem', fontWeight: 900, margin: '1rem 0' }}>₹0 <span style={{ fontSize: '0.9rem', color: '#64748b' }}>/mo</span></div>
          <ul style={listStyle}>
            <li>✅ 5 Short Links /mo</li>
            <li>✅ Basic Lead Forms</li>
            <li>✅ Static QR Codes</li>
            <li style={{ color: '#64748b' }}>❌ Advanced Analytics</li>
            <li style={{ color: '#64748b' }}>❌ Remove Branding</li>
          </ul>
          <button disabled style={{ ...btnStyle, background: 'var(--border)', cursor: 'default', color: 'var(--text-muted)' }}>
            {user?.plan === 'free' ? 'Current Plan' : 'Free Version'}
          </button>
        </div>

        {/* Pro Plan */}
        <div style={{ ...cardStyle, border: '2px solid var(--accent)', transform: 'scale(1.05)', boxShadow: '0 20px 40px rgba(0,0,0,0.3)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={badgeStyle('rgba(217, 255, 0, 0.1)', 'var(--accent)')}>PRO SUITE</div>
            <span style={{ fontSize: '0.7rem', fontWeight: 900, color: 'var(--accent)' }}>POPULAR</span>
          </div>
          <div style={{ fontSize: '2.5rem', fontWeight: 900, margin: '1rem 0' }}>₹1 <span style={{ fontSize: '0.9rem', color: '#64748b' }}>/mo</span></div>
          <ul style={listStyle}>
            <li>🔥 Unlimited Short Links</li>
            <li>🔥 Advanced Lead Tracking</li>
            <li>🔥 Professional vCards</li>
            <li>🔥 Dynamic QR Codes</li>
            <li>🔥 Remove Limitly Branding</li>
          </ul>
          <button
            onClick={handleUpgrade}
            disabled={loading || user?.plan === 'pro'}
            style={{ ...btnStyle, background: 'var(--accent)', color: 'var(--accent-text)' }}
          >
            {loading ? 'Processing...' : user?.plan === 'pro' ? 'Active Subscription' : 'Upgrade to Pro →'}
          </button>
        </div>

      </div>

      <div style={{ marginTop: '4rem', padding: '2rem', background: 'var(--card)', borderRadius: '20px', border: '1px solid var(--border)' }}>
        <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>
          🔒 Secure payments via **Razorpay**. Your data is encrypted and protected.
        </p>
      </div>
    </div>
  );
};

const cardStyle = {
  background: 'var(--card)', border: '1px solid var(--border)', borderRadius: '24px',
  padding: '2.5rem', textAlign: 'left', position: 'relative'
};

const badgeStyle = (bg, color) => ({
  background: bg, color: color, padding: '4px 12px', borderRadius: '100px',
  fontSize: '0.7rem', fontWeight: 800, letterSpacing: '1px', display: 'inline-block'
});

const listStyle = {
  listStyle: 'none', padding: 0, margin: '2rem 0', display: 'flex', flexDirection: 'column', gap: '1rem', fontSize: '0.85rem'
};

const btnStyle = {
  width: '100%', padding: '1rem', borderRadius: '14px', border: 'none',
  fontWeight: 800, fontSize: '0.9rem', cursor: 'pointer', transition: '0.2s'
};

export default Upgrade;
